@namespace Lumeo

@if (Label is not null && !InsideFormField)
{
    <label for="@EffectiveId" class="text-sm font-medium leading-none">
        @Label
        @if (Required)
        {
            <span class="text-destructive ml-0.5">*</span>
        }
    </label>
}

<div class="inline-flex items-center">
    <button type="button" id="@EffectiveId" role="switch"
            aria-checked="@Checked.ToString().ToLower()"
            aria-label="@AriaLabelValue"
            aria-required="@Required.ToString().ToLower()"
            aria-invalid="@EffectiveInvalid.ToString().ToLower()"
            aria-describedby="@FormFieldDescribedBy"
            name="@Name"
            class="@CssClass"
            @onclick="Toggle"
            disabled="@(Disabled || Loading)"
            @attributes="AdditionalAttributes">
        <span class="@ThumbClasses">
            @if (Loading)
            {
                <Spinner Size="Lumeo.Size.Sm" Class="@ThumbSpinnerClass" />
            }
        </span>
    </button>
    @if (HasOnOffLabel)
    {
        <span class="text-xs text-muted-foreground ml-2">@CurrentOnOffLabel</span>
    }
</div>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive" role="alert" aria-live="polite">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground">@HelperText</p>
    }
}

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // Inside a FormField, adopt its generated ControlId so the field's <Label For>
    // resolves to this switch button; aria-describedby announces help/error text.
    private string? FormFieldControlId => string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId;
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // Links the visible <label for> to the switch button (Checkbox pattern) so
    // clicking the label toggles the switch and AT announces the association.
    private readonly string _id = LumeoIds.New("switch");
    // A consumer `id` in the splat overrides the generated one on the button; failing
    // that the FormField's ControlId wins, then the generated id. The label's `for`
    // must point at the SAME rendered id or the association breaks (Codex P3).
    private string EffectiveId => LumeoIds.Effective(AdditionalAttributes, FormFieldControlId ?? _id);

    [Parameter] public bool Checked { get; set; }
    [Parameter] public EventCallback<bool> CheckedChanged { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool Loading { get; set; }
    [Parameter] public string? OnLabel { get; set; }
    [Parameter] public string? OffLabel { get; set; }
    /// <summary>
    /// Accessible name for the switch button, exposed via <c>aria-label</c>. Recommended
    /// for icon-only switches that have no visible text. If omitted but
    /// <see cref="OnLabel"/>/<see cref="OffLabel"/> are set, the current one is
    /// used automatically so screen readers announce the switch's purpose.
    /// </summary>
    [Parameter] public string? AriaLabel { get; set; }
    /// <summary>Switch size. Supports <see cref="Lumeo.Size.Sm"/>,
    /// <see cref="Lumeo.Size.Md"/> (default), <see cref="Lumeo.Size.Lg"/>.</summary>
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;

    /// <summary>
    /// When true, the thumb animates with a bouncy spring cubic-bezier timing
    /// instead of the default linear transition. Default is <c>false</c>.
    /// </summary>
    [Parameter] public bool Animated { get; set; }

    /// <summary>
    /// When true, triggers a short haptic vibration via <c>navigator.vibrate()</c>
    /// each time the switch is toggled. Silently no-ops on browsers without the
    /// Vibration API (e.g. iOS Safari). Default is <c>false</c>.
    /// </summary>
    [Parameter] public bool HapticFeedback { get; set; }

    [Inject] private HapticsService Haptics { get; set; } = default!;

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool HasOnOffLabel => OnLabel != null || OffLabel != null;
    private string? CurrentOnOffLabel => Checked ? OnLabel : OffLabel;

    // Prefer an explicit AriaLabel, then fall back to the currently visible On/Off text, then to Label
    // so even consumers who don't set AriaLabel get a reasonable screen-reader announcement.
    private string? AriaLabelValue => AriaLabel ?? CurrentOnOffLabel ?? Label;

    private string TrackSizeClasses => Size switch
    {
        Lumeo.Size.Sm => "h-4 w-7",
        Lumeo.Size.Lg => "h-6 w-11",
        _ => "h-5 w-9"
    };

    private string ThumbSizeClasses => Size switch
    {
        Lumeo.Size.Sm => "h-3 w-3",
        Lumeo.Size.Lg => "h-5 w-5",
        _ => "h-4 w-4"
    };

    private string ThumbTranslateClass => Size switch
    {
        Lumeo.Size.Sm => Checked ? "translate-x-3" : "translate-x-0",
        Lumeo.Size.Lg => Checked ? "translate-x-5" : "translate-x-0",
        _ => Checked ? "translate-x-4" : "translate-x-0"
    };

    private string ThumbSpinnerClass => Size switch
    {
        Lumeo.Size.Sm => "!h-2 !w-2",
        Lumeo.Size.Lg => "!h-3.5 !w-3.5",
        _ => "!h-3 !w-3"
    };

    private string CssClass => Cx.Merge(
        "peer inline-flex",
        TrackSizeClasses,
        "shrink-0 cursor-pointer items-center rounded-full border-2 border-transparent shadow-sm transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50",
        Checked ? "bg-primary" : "bg-input",
        Cx.When(EffectiveInvalid, "ring-2 ring-destructive/20 focus-visible:ring-destructive"),
        Cx.When(Loading, "pointer-events-none opacity-70"),
        Class);

    private string ThumbClasses
    {
        get
        {
            var springClass = Animated ? "lumeo-switch-spring" : null;
            return Cx.Join(
                "pointer-events-none flex items-center justify-center",
                ThumbSizeClasses,
                "rounded-full bg-background shadow-sm ring-0 transition-transform",
                ThumbTranslateClass,
                springClass);
        }
    }

    private async Task Toggle()
    {
        if (!Disabled && !Loading)
        {
            Checked = !Checked;
            await CheckedChanged.InvokeAsync(Checked);
            if (HapticFeedback) await Haptics.Light();
        }
    }

}
